bing_and_nrc &lt;- bind_rows(

  tidy_bob |&gt; 
    inner_join(get_sentiments("bing"))  |&gt; 
    mutate(method = "Bing et al."),

  tidy_bob |&gt; 
    inner_join(get_sentiments("nrc") |&gt;  
9                 filter(sentiment %in% c("positive", "negative")),
10               relationship = "many-to-many"
    )  |&gt; 
    mutate(method = "NRC"))  |&gt; 

11  count(method, episode_seq, sentiment)  |&gt;
12  pivot_wider(names_from = sentiment,
13              values_from = n,
14              values_fill = 0) |&gt;
15  mutate(sentiment = positive - negative)


